(self.webpackChunk=self.webpackChunk||[]).push([[940],{3485:(e,t,o)=>{"use strict";o.r(t),o.d(t,{data:()=>r});const r={key:"v-14114e70",path:"/about/mission.html",title:"Mission Statement",lang:"en",frontmatter:{},excerpt:"",headers:[],filePathRelative:"about/mission.md",git:{updatedTime:161838308e4}}},8087:(e,t,o)=>{"use strict";o.r(t),o.d(t,{default:()=>p});var r=o(6252);const a=(0,r.Wm)("h1",{id:"mission-statement"},[(0,r.Wm)("a",{class:"header-anchor",href:"#mission-statement"},"#"),(0,r.Uk)(" Mission Statement")],-1),n=(0,r.Wm)("p",null,"Clean energy from renewable sources should be accessible for everyone. Otherwise, how should we ever manage to limit global warming and reach the sustainable development goals?",-1),i=(0,r.Wm)("p",null,"Unfortunately, the energy supply of most countries is still controlled by some few large fossil fuel companies which try everything to keep the status quo. Their large coal and nuclear power plants should be replaced by millions of small, decentralized renewable energy generators.",-1),s=(0,r.Wm)("p",null,"Our mission is to help providing energy access for everyone and reclaim the energy supply using affordable renewable energy solutions based on open source hardware.",-1),l=(0,r.Wm)("p",null,"The primary focus of Libre Solar is solar electricity generation and storage, both for off-grid and grid-tied applications. Accordingly, the initial open source hardware projects are a MPPT charge controller and a battery management system for Lithium ion batteries.",-1),m=(0,r.Wm)("iframe",{src:"https://player.vimeo.com/video/292732744",width:"640",height:"360",frameborder:"0",webkitallowfullscreen:"",mozallowfullscreen:"",allowfullscreen:""},null,-1),h=(0,r.Wm)("p",null,[(0,r.Wm)("a",{href:"https://vimeo.com/292732744"},"Libre Solar - Explainer Video"),(0,r.Uk)(" from "),(0,r.Wm)("a",{href:"https://vimeo.com/flojoart"},"flojoART"),(0,r.Uk)(" on "),(0,r.Wm)("a",{href:"https://vimeo.com"},"Vimeo"),(0,r.Uk)(".")],-1),u=(0,r.Wm)("p",null,"Solar energy is especially suitable for decentralized and small-scale systems because the power of solar electricity generation scales linear with the area of panels. Simply put, it does not matter if you have some two or three solar panels on each roof or one large solar power plant with the same amount of panels. Small-scale solar systems might be even better, as they don’t suffer from partial shading problems.",-1),c=(0,r.Wm)("p",null,"For wind turbines, things are totally different. The power of a wind turbine grows proportional with the wind velocity to the power of three. So if you have twice the wind velocity you get eight times the power out of the same size wind turbine. Small wind turbines only have a low height and see significantly lower wind velocities compared to larger turbines in higher altitudes. So for urban regions, small wind turbines don't make much sense.",-1),d=(0,r.Wm)("p",null,"However, wind turbines can of course play an important role for the renewable energy supply in remote areas without grid access. Compatibility of the energy system with wind turbines is taken into account, but the development of wind turbines and accessories is currently not a major focus at Libre Solar.",-1),p={render:function(e,t){return(0,r.wg)(),(0,r.j4)(r.HY,null,[a,n,i,s,l,m,h,u,c,d],64)}}}}]);